namespace BgControls.Windows.DragDrop;/// <summary>/// 表示处理查询是否继续拖放（QueryContinueDrag）路由事件的方法./// </summary>/// <param name="sender">绑定事件处理程序的对象. </param>/// <param name="e">包含查询继续拖放事件数据的参数. </param>public delegate void QueryContinueDragEventHandler(object sender, QueryContinueDragEventArgs e);/// <summary>/// 为查询是否继续拖放路由事件提供数据的类./// 该类允许拖放源决定是否应取消、放置或继续拖放操作./// </summary>public sealed class QueryContinueDragEventArgs : RoutedEventArgs{    private DragAction dragAction;    /// <summary>    /// Initializes a new instance of the <see cref="QueryContinueDragEventArgs"/> class.    /// </summary>    /// <param name="e">系统原始的查询继续拖放事件参数. </param>    internal QueryContinueDragEventArgs(System.Windows.QueryContinueDragEventArgs e)        : base(e.RoutedEvent, e.OriginalSource)    {        // 将系统路由事件标识符映射到自定义的拖放管理器事件        if (e.RoutedEvent == System.Windows.DragDrop.PreviewQueryContinueDragEvent)        {            this.RoutedEvent = DragDropManager.PreviewQueryContinueDragEvent;        }        else if (e.RoutedEvent == System.Windows.DragDrop.QueryContinueDragEvent)        {            this.RoutedEvent = DragDropManager.QueryContinueDragEvent;        }        this.dragAction = e.Action;        this.EscapePressed = e.EscapePressed;        this.KeyStates = e.KeyStates;        this.Handled = e.Handled;        this.Source = e.Source;    }    /// <summary>    /// Initializes a new instance of the <see cref="QueryContinueDragEventArgs"/> class.    /// </summary>    /// <param name="action">拖放操作的状态. </param>    /// <param name="escapePressed">是否按下了 Esc 键. </param>    /// <param name="dragDropKeyStates">当前键盘和鼠标按键的状态. </param>    internal QueryContinueDragEventArgs(DragAction action, bool escapePressed, DragDropKeyStates dragDropKeyStates)    {        dragAction = action;        EscapePressed = escapePressed;        KeyStates = dragDropKeyStates;    }    /// <summary>    /// Gets or sets 关联拖放操作的状态.    /// </summary>    /// <value>    /// 一个 <see cref="DragAction"/> 枚举值，指示操作应继续、完成还是取消.    /// </value>    /// <exception cref="ArgumentException">设置了无效的枚举值时抛出. </exception>    public DragAction Action    {        get => dragAction;        set        {            if (!DragDropManager.IsValidDragAction(value))            {                throw new ArgumentException("无效的拖放操作枚举值（DragAction）.");            }            dragAction = value;        }    }    /// <summary>    /// Gets a value indicating whether 拖放过程中是否按下了 Esc 键.    /// </summary>    public bool EscapePressed { get; private set; }    /// <summary>    /// Gets 一个值，该值指示键盘按键（Shift、Ctrl、Alt）和鼠标按钮的状态.    /// </summary>    public DragDropKeyStates KeyStates { get; private set; }    /// <summary>    /// 以特定于类型的方式调用事件处理程序.l    /// 该重写通过消除泛型转换开销来提升事件的分发效率.    /// </summary>    /// <param name="genericHandler">要调用的泛型处理程序. </param>    /// <param name="genericTarget">在其上调用处理程序的源对象. </param>    protected override void InvokeEventHandler(Delegate genericHandler, object genericTarget)    {        (genericHandler as BgControls.Windows.DragDrop.QueryContinueDragEventHandler)?.Invoke(genericTarget, this);    }}